import React, { useState, useCallback } from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import Login from './pages/Login';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import NewClaim from './components/NewClaim';
import MyClaims from './components/MyClaims';
import SupervisorQueue from './components/SupervisorQueue';
import HRSQueue from './components/HRSQueue';
import { ECMQueue, DMCQueue } from './components/Queues';
import Tariffs from './components/Tariffs';
import Reports from './components/Reports';
import { Toast } from './components/Shared';

// Pages each role is allowed to visit
const ROLE_PAGES = {
  official:   ['dashboard', 'new-claim', 'my-claims'],
  supervisor: ['dashboard', 'supervisor'],
  hrs:        ['dashboard', 'hrs', 'ecm'],
  ecm:        ['dashboard', 'ecm'],
  dmc:        ['dashboard', 'dmc'],
  admin:      ['dashboard', 'tariffs', 'reports'],
};

function defaultPageForRole(role) {
  return (ROLE_PAGES[role] || ['dashboard'])[0];
}

function AppShell() {
  const { user, logout } = useAuth();
  const [page, setPage] = useState(() => defaultPageForRole(user?.role));
  const [claims, setClaims] = useState([]);
  const [toastMsg, setToastMsg] = useState('');
  const [toastVisible, setToastVisible] = useState(false);

  const toast = useCallback((msg) => {
    setToastMsg(msg);
    setToastVisible(true);
    setTimeout(() => setToastVisible(false), 3200);
  }, []);

  function updateStatus(ref, newStatus, extra = {}) {
    setClaims(prev => prev.map(c => c.ref === ref ? { ...c, status: newStatus, ...extra } : c));
  }

  const allowed = ROLE_PAGES[user?.role] || ['dashboard'];

  function onNav(id) {
    if (allowed.includes(id)) setPage(id);
  }

  const badges = {
    my:  claims.filter(c => c.persal === user?.persal).length,
    sup: claims.filter(c => c.status === 'pending').length,
    hrs: claims.filter(c => c.status === 'approved').length,
    ecm: claims.filter(c => c.status === 'ecm').length,
  };

  function renderPage() {
    if (!allowed.includes(page)) return <Navigate to="/" replace />;

    switch (page) {
      case 'dashboard':
        return <Dashboard claims={claims} onNav={onNav} user={user} />;
      case 'new-claim':
        return (
          <NewClaim
            user={user}
            onSubmit={claim => { setClaims(prev => [claim, ...prev]); setPage('my-claims'); }}
            onSaveDraft={() => toast('Draft saved')}
            toast={toast}
          />
        );
      case 'my-claims':
        return <MyClaims claims={claims.filter(c => c.persal === user?.persal)} onNav={onNav} toast={toast} />;
      case 'supervisor':
        return (
          <SupervisorQueue
            claims={claims}
            onApprove={ref => { updateStatus(ref, 'approved'); toast(ref + ' approved — sent to HRS Payroll'); }}
            onReject={ref => { updateStatus(ref, 'rejected'); toast(ref + ' rejected — official notified'); }}
          />
        );
      case 'hrs':
        return (
          <HRSQueue
            claims={claims}
            onCapture={ref => {
              const mandate = 'MAN-2026-0' + (Math.floor(Math.random() * 90) + 10);
              updateStatus(ref, 'ecm', { mandate });
              toast(ref + ' captured on Persal — mandate ' + mandate + ' uploaded to ECM');
            }}
            onReject={ref => { updateStatus(ref, 'rejected'); toast(ref + ' rejected — returned to official'); }}
          />
        );
      case 'ecm':
        return (
          <ECMQueue
            claims={claims}
            onRoute={ref => { updateStatus(ref, 'routed'); toast(ref + ' mandate routed to DMC Payroll Team Leader'); }}
          />
        );
      case 'dmc':
        return (
          <DMCQueue
            claims={claims}
            onPaid={ref => { updateStatus(ref, 'paid'); toast(ref + ' successfully paid — Persal verification confirmed'); }}
          />
        );
      case 'tariffs':
        return <Tariffs />;
      case 'reports':
        return <Reports claims={claims} toast={toast} />;
      default:
        return <Dashboard claims={claims} onNav={onNav} user={user} />;
    }
  }

  return (
    <div style={{ minHeight: '100vh', background: 'var(--bg)' }}>
      <Sidebar active={page} onNav={onNav} badges={badges} user={user} onLogout={logout} />
      <main style={{ marginLeft: 'var(--sidebar-w)', padding: '1.5rem 2rem', minHeight: '100vh' }}>
        {renderPage()}
      </main>
      <Toast message={toastMsg} visible={toastVisible} />
    </div>
  );
}

function RequireAuth({ children }) {
  const { user } = useAuth();
  if (!user) return <Navigate to="/login" replace />;
  return children;
}

function RedirectIfAuthed({ children }) {
  const { user } = useAuth();
  if (user) return <Navigate to="/" replace />;
  return children;
}

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Routes>
          <Route
            path="/login"
            element={<RedirectIfAuthed><Login /></RedirectIfAuthed>}
          />
          <Route
            path="/*"
            element={<RequireAuth><AppShell /></RequireAuth>}
          />
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}
